+                         "Filesystem path to the point cloud", this, SLOT(updateCloud()));
+    frame_property_ = new rviz::TfFrameProperty("Reference Frame", rviz::TfFrameProperty::FIXED_FRAME_STRING,
+                          "The TF frame this point cloud will use for its origin.", this, 0, true, SLOT(updateOrigin()));
+    origin_offset_property_ = new rviz::VectorProperty("Offset", Ogre::Vector3::ZERO,
+                                  "Allows you to offset the point cloud from the origin of the reference frame.",
+                                  this, SLOT(updateOrigin()));
+    origin_rotation_property_ = new rviz::QuaternionProperty("Rotation", Ogre::Quaternion::IDENTITY,
+                                    "Allows you to rotate the point cloud w.r.t. the origin of the reference frame.",
+                                    this, SLOT(updateOrigin()));
+    point_budget_property_ = new rviz::IntProperty("Point Budget", 1000000,
+                                 "Set the rendering budget. The more points, the more detailed the view.",
+                                 this, SLOT(updateRenderOptions()));
+    point_budget_property_->setMin(100000);
+    point_budget_property_->setMax(20000000);
