+                           this, SLOT(updateRenderOptions()));
+    point_size_property_->setMin(1);
+    point_size_property_->setMax(50.0);
+    hq_render_property_ = new rviz::BoolProperty("HQ Rendering", false,
+                          "Use HQ splats for better visual quality.",
+                          this, SLOT(updateRenderOptions()));
+    hq_render_property_->setDisableChildrenIfFalse(true);
+    shading_property_ = new rviz::BoolProperty("Shaded Outlines", false,
+                        "Render HQ splats with shaded outlines for more distinctive edges",
+                        hq_render_property_, SLOT(updateRenderOptions()), this);
+}
+
+void PotreeDisplay::onInitialize()
+{
+    frame_property_->setFrameManager(context_->getFrameManager());
+}
+
+void PotreeDisplay::onEnable()
+{
+    updateCloud();
+}
+
+void PotreeDisplay::onDisable()
+{
+    visual_.reset();
+}
