+void PotreeDisplay::fixedFrameChanged()
+{
+    updateOrigin();
+}
+
+void PotreeDisplay::updateOrigin()
+{
+    Ogre::Vector3 position, pos_offset;
+    Ogre::Quaternion orientation, ori_offset;
+    rviz::FrameManager* m = context_->getFrameManager();
+    std::string error_msg;
+    if (m->transformHasProblems(frame_property_->getFrameStd(), ros::Time(), error_msg))
+    {
+        setStatus(rviz::StatusProperty::Error, "Transform", QString::fromStdString(error_msg));
+        if (visual_) visual_->setVisible(false);
+        return;
+    }
+    if (!m->getTransform(frame_property_->getFrameStd(), ros::Time(), position, orientation))
+    {
+        ROS_ERROR("Unexpected error transforming from frame '%s' to frame '%s'", qPrintable(frame_property_->getFrame()),
+                qPrintable( fixed_frame_ ));
+        if (visual_) visual_->setVisible(false);
+        return;
+    }
+    pos_offset = origin_offset_property_->getVector();
+    ori_offset = origin_rotation_property_->getQuaternion();
+    position += orientation * pos_offset;
+    if (std::abs(ori_offset.Norm() - 1.f) < 1e-2) orientation = orientation * ori_offset;
+    if (visual_)
+    {
+        visual_->setVisible(true);
+        visual_->setOrigin(position, orientation);
+    }
+    setStatus(rviz::StatusProperty::Ok, "Transform", "Transform OK");
+}
+
+void PotreeDisplay::updateRenderOptions()
+{
+    if (visual_)
+    {
+        visual_->setPointBudget(point_budget_property_->getInt());
+        visual_->setPointSize(point_size_property_->getFloat());
+        visual_->enableHQRendering(hq_render_property_->getBool(), shading_property_->getBool());
+    }
+}
+
+void PotreeDisplay::updateCloud()
+{
+    visual_.reset(); // first delete the old point cloud from memory, if any
+    if (!isEnabled()) return;
+    std::string error_msg;
+    fs::path path = path_property_->getStdString();
+    if (!CloudLoader::isValid(path, error_msg))
+    {
+        setStatus(rviz::StatusProperty::Error, "Cloud", QString::fromStdString(error_msg));
+        return;
+    }
+    try
+    {
+        std::shared_ptr<CloudLoader> loader = std::make_shared<CloudLoader>(path);
+        visual_ = std::make_shared<PotreeVisual>(loader, context_->getSceneManager(), scene_node_);
+        setStatus (rviz::StatusProperty::Ok, "Cloud", QString("%1 points").arg(loader->metaData()->pointCount()));
+        updateOrigin();
+        updateRenderOptions();
+    }
+    catch (std::exception& e)
+    {
+        setStatus(rviz::StatusProperty::Error, "Cloud", e.what());
+    }
+}
