+bool is_different (const Ogre::Matrix4& m1, const Ogre::Matrix4& m2, double eps = 1e-3)
+{
+    for (int i = 0; i < 4; ++i)
+    {
+        for (int j = 0; j < 4; ++j)
+        {
+            if (std::abs(m1[i][j] - m2[i][j]) > eps) return true;
+        }
+    }
+    return false;
+}
